1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	  enchantment?: number;
5	}
6	
7	interface QuoteStep {
8	  op: "quote";
9	  items: QuoteItem[];
10	}
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: QuoteStep[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  amulet: 60,
19	  sword: 100,
20	};
21	
22	const FIRST_INSURANCE_RATE = 0.1;
23	const PROCESSING_FEE = 5;
24	
25	const CURSE_SURCHARGE_RATE = 0.5;
26	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
27	const HIGH_ENCHANTMENT_THRESHOLD = 5;
28	const LOYALTY_DISCOUNT_RATE = 0.2;
29	const LOYALTY_THRESHOLD_YEARS = 2;
30	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
31	
32	function sumOver<T>(xs: T[], f: (x: T) => number): number {
33	  return xs.reduce((total, x) => total + f(x), 0);
34	}
35	
36	// MHPCO rounds quote premiums UP (in the office's favor).
37	function roundUpInFavorOfOffice(amount: number): number {
38	  return Math.ceil(amount);
39	}
40	
41	function itemBasePremium(item: QuoteItem): number {
42	  return BASE_PREMIUM[item.type] ?? 0;
43	}
44	
45	function itemSurcharges(item: QuoteItem): number {
46	  const base = itemBasePremium(item);
47	  const curseSurcharge = item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
48	  const highEnchantmentSurcharge =
49	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
50	      ? base * HIGH_ENCHANTMENT_SURCHARGE_RATE
51	      : 0;
52	  return curseSurcharge + highEnchantmentSurcharge;
53	}
54	
55	function priceQuoteStep(
56	  step: QuoteStep,
57	  yearsWithMHPCO: number,
58	  isFollowUp: boolean,
59	): { premium: number } {
60	  const policyBase = sumOver(step.items, itemBasePremium);
61	  const itemSurchargeTotal = sumOver(step.items, itemSurcharges);
62	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
63	  const loyaltyDiscount =
64	    yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS
65	      ? policyBase * LOYALTY_DISCOUNT_RATE
66	      : 0;
67	  const followUpDiscount = isFollowUp
68	    ? policyBase * FOLLOW_UP_DISCOUNT_RATE
69	    : 0;
70	  const premium = roundUpInFavorOfOffice(
71	    policyBase +
72	      itemSurchargeTotal +
73	      firstInsurance -
74	      loyaltyDiscount -
75	      followUpDiscount +
76	      PROCESSING_FEE,
77	  );
78	  return { premium };
79	}
80	
81	export function runScenario(scenario: Scenario): {
82	  results: { premium: number }[];
83	} {
84	  const results = scenario.steps.map((step, index) =>
85	    priceQuoteStep(step, scenario.customer.yearsWithMHPCO, index > 0),
86	  );
87	  return { results };
88	}
